#!/usr/bin/env node
/* Builds shared/gf-db-bundle.js from db/*.json so the browser can load all
 * shop data via a single <script> tag — works on file:// (no fetch/CORS).
 * Run after editing any JSON file under db/. */
const fs   = require('fs');
const path = require('path');
const root = path.resolve(__dirname, '..');

const products = ['seeds','saplings','minerals','compost']
  .flatMap(f => JSON.parse(fs.readFileSync(path.join(root,'db/products',f+'.json'),'utf8')));
const tools    = ['hand-tools','irrigation','containers','support','protection','diagnostics','propagation','pest-control','safety-gear']
  .flatMap(f => JSON.parse(fs.readFileSync(path.join(root,'db/tools',   f+'.json'),'utf8')));
const shopCfg  = JSON.parse(fs.readFileSync(path.join(root,'db/shop-config.json'),'utf8'));
const climate  = {
  zones:      JSON.parse(fs.readFileSync(path.join(root,'db/climate/zones.json'),'utf8')),
  stateZone:  JSON.parse(fs.readFileSync(path.join(root,'db/climate/state-zone-map.json'),'utf8')),
  rdBuckets:  JSON.parse(fs.readFileSync(path.join(root,'db/climate/rd-buckets.json'),'utf8'))
};

const all = [...products, ...tools];
// Dedupe by id (tools/products override inline if conflicting)
const seen = new Map();
all.forEach(p => seen.set(p.id, p));
const merged = [...seen.values()].sort((a,b)=>a.id-b.id);

const out = `/* AUTO-GENERATED by scripts/build-db-bundle.js — do not edit by hand.
 * Edit the JSON files in db/ and re-run:  node scripts/build-db-bundle.js
 * Build time: ${new Date().toISOString()}
 * Items: ${merged.length} (${products.length} products + ${tools.length} tools)
 */
window.GF_PRODUCTS    = ${JSON.stringify(merged)};
window.GF_SHOP_CONFIG = ${JSON.stringify(shopCfg)};
window.GF_CLIMATE     = ${JSON.stringify(climate)};
window._gfProductsLoaded = true;
window._gfToolsLoaded    = true;
`;
fs.writeFileSync(path.join(root,'shared/gf-db-bundle.js'), out);
console.log('✓ shared/gf-db-bundle.js  ('+merged.length+' items, '+(out.length/1024|0)+' KB)');
